fn chirality_rank(chirality: Chirality) -> u8 {
    match chirality {
        Chirality::Intake => 0,
        Chirality::Compression => 1,
        Chirality::Ignition => 2,
        Chirality::Exhaust => 3,
        Chirality::Interference => 4,
    }
}

// ─────────────────────────────────────────────────────────────────────
// Ergonomic Stoplight constructors (AMQP-flavored)
// ─────────────────────────────────────────────────────────────────────

/// Stoplight constructors that match `basic.qos` semantics directly:
/// `green` is prefetch width, `cycle` is the corridor period.
pub trait StoplightExt {
    /// "Resting" corridor: `cycle` ticks total, `green` ticks of admission
    /// per cycle, fixed `offset`. Travel/speed are 0 — this is a wall
    /// (not a road) so the Lean `travelTime` term drops out.
    fn resting(cycle: u32, green: u32, offset: u32) -> Self;

    /// "Open" corridor: green for the full cycle. Equivalent to unbounded
    /// prefetch (no rate gate). Useful for development; production code
    /// should pick a finite green width tied to the bottleneck service rate.
    fn open(cycle: u32) -> Self;
}

impl StoplightExt for Stoplight {
    #[inline]
    fn resting(cycle: u32, green: u32, offset: u32) -> Self {
        Stoplight::new(cycle, green, offset, 0, 1)
    }

    #[inline]
    fn open(cycle: u32) -> Self {
        Stoplight::new(cycle, cycle, 0, 0, 1)
    }
}

// ─────────────────────────────────────────────────────────────────────
// Message envelope
// ─────────────────────────────────────────────────────────────────────

/// One AMQP-shaped message. The body is opaque bytes; routing key is the
/// dotted-segment string consumed by topic/direct exchanges.
#[derive(Clone, Debug)]
pub struct Message {
    /// Dotted routing key (`compute`, `tasks.compute`, `logs.error.fatal`).
    pub routing_key: String,
    /// AMQP-style headers map for `headers`-exchange matching.
    pub headers: HashMap<String, String>,
    /// Opaque message body.
    pub body: Vec<u8>,
}

impl Message {
    /// Construct a message with the given routing key and body, no headers.
    #[inline]
    pub fn new(routing_key: impl Into<String>, body: impl Into<Vec<u8>>) -> Self {
        Self {
            routing_key: routing_key.into(),
            headers: HashMap::new(),
            body: body.into(),
        }
    }

    /// Attach one header. Builder-style.
    #[inline]
    pub fn with_header(mut self, k: impl Into<String>, v: impl Into<String>) -> Self {
        self.headers.insert(k.into(), v.into());
        self
    }
}

// ─────────────────────────────────────────────────────────────────────
// Consumer registration
// ─────────────────────────────────────────────────────────────────────

/// Handler function type. Returns Ok for `basic.ack`, Err for `basic.nack`.
pub type Handler = Arc<dyn Fn(&Message) -> Result<(), String> + Send + Sync>;

/// Live consumer registration on the broker. Holds the Stoplight that
/// gates its admission and the handler that runs at the green tick.
struct Consumer {
    /// AMQP queue name. In AMQP this is the queue's identity; here it is
    /// also the routing-key match target for `Direct` exchanges (per the
    /// usual AMQP convention where queue name == binding key for direct).
    #[allow(dead_code)]
    name: String,
    /// Admission Stoplight. `green` is prefetch; `cycle` is the corridor
    /// period.
    light: Stoplight,
    /// Wankel chamber assignment (intake/compression/...). Recorded so a
    /// downstream `Channel` can pivot dispatch on stage.
    chirality: Chirality,
    /// Message handler. Returns Ok to ack, Err to nack.
    handler: Handler,
    /// Certified per-message handler cost (ns) — the value-door cost class.
    /// Sourced from the consumer's `QosSpec` cert at declare time. The
    /// cost-aware publish path reads this to decide RED (cheap: run inline,
    /// skip the corridor stagger) vs GREEN (heavy: open the staggered door).
    /// `0` = unattested → conservatively heavy (keep the stagger). The default
    /// publish path never reads it.
    handler_cost_ns: u64,
    /// Phase-feedback offset that grows when this consumer nacks. Read by
    /// producers on the next publish to widen the upstream offset (so a
    /// flapping consumer admits messages later in the cycle, giving its
    /// upstream room to recover). Atomic so the producer's rate-gate read
    /// is lock-free on the hot path.
    nack_offset: AtomicU32,
    /// Lifetime counters. Used by `Telemetry` (no per-message lock).
    delivered: AtomicUsize,
    nacked: AtomicUsize,
    dropped: AtomicUsize,
}

// ─────────────────────────────────────────────────────────────────────
// Exchanges + bindings (per-broker, RwLock)
// ─────────────────────────────────────────────────────────────────────

/// Per-broker exchange table. Bindings live inside each exchange.
struct ExchangeTable {
    /// Exchange name -> (kind, bindings).
    exchanges: HashMap<String, ExchangeRecord>,
}

struct ExchangeRecord {
    kind: ExchangeKind,
    bindings: Vec<Binding>,
}

#[derive(Clone, Debug, Eq, Hash, PartialEq)]
struct RouteCacheKey {
    exchange: String,
    routing_key: String,
}

struct RouteCacheEntry {
    epoch: u64,
    queues: Vec<String>,
}

struct RouteObservation {
    epoch: u64,
    count: u8,
}

struct RouteAdmissionCache {
    entries: HashMap<RouteCacheKey, RouteCacheEntry>,
    observations: HashMap<RouteCacheKey, RouteObservation>,
}

const ROUTE_CACHE_ADMISSION_OBSERVATIONS: u8 = 3;

impl RouteAdmissionCache {
    fn new() -> Self {
        Self {
            entries: HashMap::new(),
            observations: HashMap::new(),
        }
    }

    fn get(&self, key: &RouteCacheKey, epoch: u64) -> Option<Vec<String>> {
        self.entries
            .get(key)
            .filter(|entry| entry.epoch == epoch)
            .map(|entry| entry.queues.clone())
    }

    fn observe(&mut self, key: RouteCacheKey, epoch: u64, queues: Vec<String>) {
        if self
            .entries
            .get(&key)
            .is_some_and(|entry| entry.epoch == epoch)
        {
            return;
        }

        let observation = self
            .observations
            .entry(key.clone())
            .or_insert(RouteObservation { epoch, count: 0 });

        if observation.epoch != epoch {
            observation.epoch = epoch;
            observation.count = 0;
        }

        observation.count = observation.count.saturating_add(1);
        if observation.count >= ROUTE_CACHE_ADMISSION_OBSERVATIONS {
            self.entries.insert(key, RouteCacheEntry { epoch, queues });
        }
    }

    fn clear(&mut self) {
        self.entries.clear();
        self.observations.clear();
    }
}

impl ExchangeTable {
    fn new() -> Self {
        let mut t = Self {
            exchanges: HashMap::new(),
        };
        // Default exchange (unnamed direct, per AMQP 0-9-1 §3.1.3.3).
        t.exchanges.insert(
            String::new(),
            ExchangeRecord {
                kind: ExchangeKind::Direct,
                bindings: Vec::new(),
            },
        );
        t
    }

    fn declare(&mut self, name: &str, kind: ExchangeKind) {
        self.exchanges
            .entry(name.to_string())
            .or_insert_with(|| ExchangeRecord {
                kind,
                bindings: Vec::new(),
            });
    }

    fn bind(&mut self, exchange: &str, binding: Binding) {
        if let Some(rec) = self.exchanges.get_mut(exchange) {
            rec.bindings.push(binding);
        }
    }

    fn route(&self, exchange: &str, msg: &Message) -> Option<(ExchangeKind, Vec<String>)> {
        let rec = self.exchanges.get(exchange)?;
        let queues: Vec<&str> = match rec.kind {
            ExchangeKind::Direct => rec
                .bindings
                .iter()
                .filter(|b| b.key.matches_direct(&msg.routing_key))
                .map(|b| b.queue.as_str())
                .collect(),
            ExchangeKind::Topic => rec
                .bindings
                .iter()
                .filter(|b| b.key.matches_topic(&msg.routing_key))
                .map(|b| b.queue.as_str())
                .collect(),
            ExchangeKind::Fanout => rec.bindings.iter().map(|b| b.queue.as_str()).collect(),
            ExchangeKind::Headers => rec
                .bindings
                .iter()
                .filter(|b| b.key.matches_headers(&msg.headers))
                .map(|b| b.queue.as_str())
                .collect(),
        };
        Some((
            rec.kind,
            queues.into_iter().map(ToString::to_string).collect(),
        ))
    }
}

// ─────────────────────────────────────────────────────────────────────
// Broker
// ─────────────────────────────────────────────────────────────────────

/// Telemetry snapshot returned by `Broker::telemetry`.
#[derive(Clone, Copy, Debug, Default)]
pub struct Telemetry {
    /// Total messages published successfully.
    pub published: usize,
    /// Total messages delivered to a handler (handler returned Ok).
    pub delivered: usize,
    /// Total nacks (handler returned Err). These widen upstream offset.
    pub nacked: usize,
    /// Total messages dropped (no matching consumer, or vent under DLX mock).
    pub dropped: usize,
    /// Observed peak in-flight count across all consumers. Bounded by the
    /// sum of `green` widths — this is the antiqueue invariant.
    pub peak_in_flight: usize,
}

/// The broker. Holds the exchange table, the consumer registry, and the
/// shared monotonic clock used by `corridor_all_green` rate-gating.
pub struct Broker {
    exchanges: RwLock<ExchangeTable>,
    consumers: RwLock<HashMap<String, Arc<Consumer>>>,
    route_cache: RwLock<RouteAdmissionCache>,
    route_topology_epoch: AtomicU64,
    #[cfg(test)]
    route_cache_hits: AtomicUsize,
    /// Shared monotonic clock used to convert elapsed time to corridor ticks. Set once at broker
    /// construction; producers read it on every publish to compute the current corridor tick. Native:
    /// wall-clock `Instant`. Wasm: a logical tick counter (no wall clock on `wasm32-unknown-unknown`).
    clock: MonoClock,
    /// One corridor tick in wall-clock duration. Default 1 ms (matches
    /// the TS reference). Tunable via `Broker::with_tick`.
    tick: Duration,
    /// Per-broker in-flight counter (across all consumers). Producers
    /// observe this to honor the antiqueue invariant.
    in_flight: AtomicUsize,
    peak_in_flight: AtomicUsize,
    /// Telemetry totals.
    published: AtomicUsize,
}

impl Broker {
    /// Construct a local in-process broker with 1 ms ticks.
    pub fn local() -> Arc<Self> {
        Arc::new(Self {
            exchanges: RwLock::new(ExchangeTable::new()),
            consumers: RwLock::new(HashMap::new()),
            route_cache: RwLock::new(RouteAdmissionCache::new()),
            route_topology_epoch: AtomicU64::new(0),
            #[cfg(test)]
            route_cache_hits: AtomicUsize::new(0),
            clock: MonoClock::start(),
            tick: Duration::from_millis(1),
            in_flight: AtomicUsize::new(0),
            peak_in_flight: AtomicUsize::new(0),
            published: AtomicUsize::new(0),
        })
    }

    /// Construct a broker with a custom tick duration. Use sub-ms ticks
    /// for in-process micro-benchmarks where setTimeout-floor is absent.
    pub fn with_tick(tick: Duration) -> Arc<Self> {
        Arc::new(Self {
            exchanges: RwLock::new(ExchangeTable::new()),
            consumers: RwLock::new(HashMap::new()),
            route_cache: RwLock::new(RouteAdmissionCache::new()),
            route_topology_epoch: AtomicU64::new(0),
            #[cfg(test)]
            route_cache_hits: AtomicUsize::new(0),
            clock: MonoClock::start(),
            tick,
            in_flight: AtomicUsize::new(0),
            peak_in_flight: AtomicUsize::new(0),
            published: AtomicUsize::new(0),
        })
    }

    /// Declare an exchange. Idempotent (matching AMQP 0-9-1).
    pub fn declare_exchange(&self, name: &str, kind: ExchangeKind) {
        self.exchanges.write().unwrap().declare(name, kind);
        self.invalidate_route_cache();
    }

    /// Bind a queue to an exchange under a binding key. The queue is
    /// identified by its consumer name (AMQP queue name).
    pub fn bind(&self, exchange: &str, queue: &str, key: BindingKey) {
        self.exchanges.write().unwrap().bind(
            exchange,
            Binding {
                queue: queue.to_string(),
                key,
            },
        );
        self.invalidate_route_cache();
    }

    /// Declare a consumer ("queue") with a Stoplight admission gate and a
    /// handler. Replaces AMQP's `queue.declare` + `basic.consume` pair:
    /// here there is no separate queue object — the consumer *is* the
    /// queue, and there is no buffer behind it. The handler runs on the
    /// publisher's thread once the corridor is all-green.
    ///
    /// `chirality` defaults to `Compression` (the "do work" chamber).
    /// For pipelines that need explicit chamber labeling, call
    /// `declare_consumer_with_chirality`.
    pub fn declare_consumer(
        self: &Arc<Self>,
        name: &str,
        light: Stoplight,
        handler: impl Fn(&Message) -> Result<(), String> + Send + Sync + 'static,
    ) {
        self.declare_consumer_with_chirality(name, light, Chirality::Compression, handler);
    }

    /// As `declare_consumer`, but with an explicit Wankel chamber slot.
    pub fn declare_consumer_with_chirality(
        self: &Arc<Self>,
        name: &str,
        light: Stoplight,
        chirality: Chirality,
        handler: impl Fn(&Message) -> Result<(), String> + Send + Sync + 'static,
    ) {
        // Cost class 0 (unattested): the cost-aware publish path treats this
        // consumer as heavy (always staggered). The default publish path is
        // unaffected — it never reads the cost.
        self.declare_consumer_certified(name, light, chirality, 0, handler);
    }

    /// As `declare_consumer_with_chirality`, but ALSO attests the per-message
    /// handler cost (`handler_cost_ns`) — the value-door cost class read by the
    /// cost-aware publish path (`Producer::publish_message_certified`). This is
    /// additive: it changes nothing about the default (size/green-window-gated)
    /// `publish` path; it only supplies the cert the cost gate reads. A cost of
    /// `0` is treated as unattested → conservatively heavy (keep the stagger).
    ///
    /// The cert is sourced exactly as `gnosis-frf`'s `execute_with_certified_cost`
    /// sources its per-item work from admission — here the admission is the
    /// consumer's QoS cert (AMQP `prefetch_size` reinterpreted as a cost class).
    pub fn declare_consumer_certified(
        self: &Arc<Self>,
        name: &str,
        light: Stoplight,
        chirality: Chirality,
        handler_cost_ns: u64,
        handler: impl Fn(&Message) -> Result<(), String> + Send + Sync + 'static,
    ) {
        // Auto-bind to the default direct exchange under the queue name,
        // per AMQP 0-9-1 §3.1.3.3.
        let consumer = Arc::new(Consumer {
            name: name.to_string(),
            light,
            chirality,
            handler: Arc::new(handler),
            handler_cost_ns,
            nack_offset: AtomicU32::new(0),
            delivered: AtomicUsize::new(0),
            nacked: AtomicUsize::new(0),
            dropped: AtomicUsize::new(0),
        });
        self.consumers
            .write()
            .unwrap()
            .insert(name.to_string(), consumer);
        self.invalidate_route_cache();
        self.bind("", name, BindingKey::Direct(name.to_string()));
    }

    /// Construct a producer bound to the given exchange. Empty string for
    /// the default direct exchange (AMQP convention).
    pub fn producer(self: &Arc<Self>, exchange: &str) -> Producer {
        Producer {
            broker: Arc::clone(self),
            exchange: exchange.to_string(),
        }
    }

    fn invalidate_route_cache(&self) {
        self.route_topology_epoch.fetch_add(1, Ordering::AcqRel);
        self.route_cache.write().unwrap().clear();
    }

    fn route_queues(&self, exchange: &str, msg: &Message) -> Vec<String> {
        let key = RouteCacheKey {
            exchange: exchange.to_string(),
            routing_key: msg.routing_key.clone(),
        };
        let epoch = self.route_topology_epoch.load(Ordering::Acquire);

        if let Some(queues) = self.route_cache.read().unwrap().get(&key, epoch) {
            #[cfg(test)]
            self.route_cache_hits.fetch_add(1, Ordering::Relaxed);
            return self.stable_consumer_route_order(queues);
        }

        let Some((kind, queues)) = self.exchanges.read().unwrap().route(exchange, msg) else {
            return Vec::new();
        };

        if matches!(
            kind,
            ExchangeKind::Direct | ExchangeKind::Topic | ExchangeKind::Fanout
        ) {
            self.route_cache
                .write()
                .unwrap()
                .observe(key, epoch, queues.clone());
        }

        self.stable_consumer_route_order(queues)
    }

    fn stable_consumer_route_order(&self, queues: Vec<String>) -> Vec<String> {
        if queues.len() <= 1 {
            return queues;
        }

        let now_tick = self.current_tick();
        let consumers_lock = self.consumers.read().unwrap();
        
        let mut indexed: Vec<(usize, &Arc<Consumer>)> = Vec::with_capacity(queues.len());
        for (i, q) in queues.iter().enumerate() {
            if let Some(c) = consumers_lock.get(q) {
                indexed.push((i, c));
            }
        }

        indexed.sort_by_key(|(declaration_order, consumer)| {
            let nack_offset = consumer.nack_offset.load(Ordering::Acquire);
            let cycle = consumer.light.cycle.max(1);
            let effective_light = Stoplight::new(
                consumer.light.cycle,
                consumer.light.green,
                consumer
                    .light
                    .offset
                    .wrapping_add(nack_offset)
                    .checked_rem(cycle)
                    .unwrap_or(0),
                consumer.light.distance,
                consumer.light.speed,
            );
            let earliest = earliest_green_start(effective_light);
            let mut target = earliest;
            if target < now_tick {
                let delta = now_tick - target;
                let k = (delta + cycle - 1) / cycle;
                target = target.saturating_add(k.saturating_mul(cycle));
            }
            (
                target.saturating_sub(now_tick),
                chirality_rank(consumer.chirality),
                nack_offset,
                *declaration_order,
            )
        });
        indexed.into_iter().map(|(_, c)| c.name.clone()).collect()
    }

    /// Snapshot telemetry. Cheap (atomic loads); safe to call at any rate.
    pub fn telemetry(&self) -> Telemetry {
        let consumers = self.consumers.read().unwrap();
        let mut t = Telemetry {
            published: self.published.load(Ordering::Acquire),
            delivered: 0,
            nacked: 0,
            dropped: 0,
            peak_in_flight: self.peak_in_flight.load(Ordering::Acquire),
        };
        for c in consumers.values() {
            t.delivered += c.delivered.load(Ordering::Acquire);
            t.nacked += c.nacked.load(Ordering::Acquire);
            t.dropped += c.dropped.load(Ordering::Acquire);
        }
        t
    }

    /// Per-message corridor-gate cost in nanoseconds — the dispatch side of
    /// the value-door crossover, the antiqueue analogue of `gnosis-frf`'s
    /// `per_item_dispatch_ns`. This is what staggering one message into its
    /// green window costs over running it inline now: the `current_tick` /
    /// `earliest_green_start` / cycle-shift arithmetic plus the
    /// `wait_for_tick` spin/sleep coordination.
    ///
    /// Floored at the broker tick width (the smallest stagger the corridor can
    /// express is one tick — a message held to its green window waits at least
    /// that long), plus a fixed arithmetic/atomic overhead. Overridable via
    /// `GNOSIS_ANTIQUEUE_GATE_NS` for platform calibration.
    ///
    /// The cost-aware publish path opens the staggered door only when the
    /// certified per-message handler cost exceeds this gate cost
    /// (`certified_light` → GREEN); cheaper messages run inline (RED).
    #[inline]
    fn per_message_gate_ns(&self) -> u64 {
        use std::sync::atomic::AtomicU64;
        static OVERRIDE: AtomicU64 = AtomicU64::new(0);
        const SENTINEL_UNSET: u64 = u64::MAX;
        let cached = OVERRIDE.load(Ordering::Relaxed);
        if cached == SENTINEL_UNSET {
            return 0; // explicitly disabled via env=0
        }
        if cached != 0 {
            return cached;
        }
        if let Some(v) = std::env::var("GNOSIS_ANTIQUEUE_GATE_NS")
            .ok()
            .and_then(|s| s.parse::<u64>().ok())
        {
            OVERRIDE.store(if v == 0 { SENTINEL_UNSET } else { v }, Ordering::Relaxed);
            return v;
        }
        // Tick width is the floor on stagger cost; +200ns covers the
        // tick/green-window arithmetic and the in-flight atomics.
        let tick_ns = self.tick.as_nanos().min(u64::MAX as u128) as u64;
        tick_ns.saturating_add(200)
    }

    /// Current corridor tick (elapsed since broker construction, floor-divided by tick width).
    /// Native: wall-clock. Wasm: the logical monotonic tick (see [`crate::clock::MonoClock`]).
    #[inline]
    fn current_tick(&self) -> u32 {
        self.clock.current_tick(self.tick)
    }

    /// Block until `target_tick` arrives on the broker clock. Native: spin/sleep to the wall-clock
    /// deadline. Wasm: a no-op (no clock/threads; the host paces frames — see [`crate::clock`]).
    fn wait_for_tick(&self, target_tick: u32) {
        self.clock.wait_for_tick(target_tick, self.tick);
    }

    /// Observe a possibly-new peak in-flight count.
    #[inline]
    fn observe_peak(&self, depth: usize) {
        let mut prev = self.peak_in_flight.load(Ordering::Relaxed);
        while depth > prev {
            match self.peak_in_flight.compare_exchange_weak(
                prev,
                depth,
                Ordering::Relaxed,
                Ordering::Relaxed,
            ) {
                Ok(_) => return,
                Err(seen) => prev = seen,
            }
        }
    }
}

// ─────────────────────────────────────────────────────────────────────
// Producer (the rate-gated entry point)
// ─────────────────────────────────────────────────────────────────────

/// A handle for publishing to a specific exchange. Cheap to clone.
#[derive(Clone)]
pub struct Producer {
    broker: Arc<Broker>,
    exchange: String,
}

impl Producer {
    /// Publish a message. Maps to `exchange.publish` in AMQP, but the
    /// admission is gated by the matched consumer's Stoplight — we wait
    /// until `seesGreen(now, light)` is true before the handler runs.
    ///
    /// Returns the number of consumers the message was delivered to (0
    /// if no binding matched; the message is dropped, mocking DLX).
    pub fn publish(&self, routing_key: &str, body: impl Into<Vec<u8>>) -> Result<usize, String> {
        self.publish_message(Message::new(routing_key, body))
    }

    /// Cost-aware publish — routes through the value-door crossover. See
    /// [`Producer::publish_message_certified`]. Cheap messages (RED) run
    /// inline; heavy ones (GREEN) stagger into the green window.
    pub fn publish_certified(
        &self,
        routing_key: &str,
        body: impl Into<Vec<u8>>,
    ) -> Result<usize, String> {
        self.publish_message_certified(Message::new(routing_key, body))
    }

    /// As `publish` but accepts a pre-built `Message` (headers, etc.).
    ///
    /// DEFAULT path: every matched consumer's message is staggered into its
    /// green window (the size/green-window gate). This is unchanged — the
    /// cost-aware crossover lives in the additive sibling
    /// [`Producer::publish_message_certified`].
    pub fn publish_message(&self, msg: Message) -> Result<usize, String> {
        // `decide_stagger` always GREEN: the default gate is the green window,
        // not the per-message cost crossover.
        self.dispatch(msg, |_consumer, _broker| true)
    }

    /// CERTIFIED, cost-aware publish — the value-door crossover seen from the
    /// scheduling side. Additive sibling of [`Producer::publish_message`]:
    /// identical dispatch core, identical green-window math; the ONLY
    /// difference is the gate.
    ///
    /// For each matched consumer, read its certified per-message handler cost
    /// (`Consumer::handler_cost_ns`, sourced from the QoS cert at declare time)
    /// and compare it to the per-message gate cost (`Broker::per_message_gate_ns`,
    /// the antiqueue analogue of `gnosis-frf`'s `per_item_dispatch_ns`):
    ///
    ///   * RED  (`handler_cost <= gate_cost`): the corridor stagger costs more
    ///     than handling the message — stay laminar. Run the handler INLINE,
    ///     now, skipping `wait_for_tick`. This is the fast lane that dodges the
    ///     "cheap message pays the full stagger" trap.
    ///   * GREEN (`gate_cost < handler_cost`): the work pays for the door —
    ///     stagger into the green window exactly as the default path does.
    ///
    /// A cost of `0` is unattested → conservatively GREEN (keep the stagger).
    /// The decision is `Gnosis.ValueDoorStoplight.certified_light`: a cert in
    /// hand is always RED or GREEN, never the YELLOW probe.
    pub fn publish_message_certified(&self, msg: Message) -> Result<usize, String> {
        self.dispatch(msg, |consumer, broker| {
            // 0 = unattested → treat as heavy (GREEN / stagger).
            if consumer.handler_cost_ns == 0 {
                return true;
            }
            let gate = broker.per_message_gate_ns();
            // GREEN iff the certified handler cost beats the gate cost.
            matches!(
                value_door::certified_light(consumer.handler_cost_ns, gate),
                Light::Green
            )
        })
    }

    /// Shared dispatch core. Routes the message to each matched consumer; the
    /// `decide_stagger` closure chooses, per consumer, whether to stagger into
    /// the green window (`true` → the door) or run inline now (`false` → RED,
    /// laminar). Both `publish_message` (always-stagger) and
    /// `publish_message_certified` (cost-gated) route through here so the only
    /// thing that varies is the gate, never the dispatch — mirroring
    /// `gnosis-frf`'s `execute_with_k_eff`.
    fn dispatch(
        &self,
        msg: Message,
        decide_stagger: impl Fn(&Consumer, &Broker) -> bool,
    ) -> Result<usize, String> {
        self.broker.published.fetch_add(1, Ordering::Relaxed);

        // Route through the exchange. Note we copy queue names out of the
        // RwLock so we don't hold it while invoking handlers (which would
        // deadlock if a handler called back into `Broker::declare_*`).
        let queues = self.broker.route_queues(&self.exchange, &msg);

        if queues.is_empty() {
            // No binding matched — DLX mock (vent).
            return Ok(0);
        }

        let mut delivered = 0usize;
        let consumers_lock = self.broker.consumers.read().unwrap();
        for q in &queues {
            let Some(consumer) = consumers_lock.get(q) else { continue };

            // The value-door gate: stagger into the green window, or stay
            // laminar (RED) and run inline now.
            if decide_stagger(consumer, &self.broker) {
                // Compute the earliest green tick for this consumer, advanced
                // by any accumulated nack_offset (phase feedback). The wait is
                // relative to the producer's *current* corridor tick.
                let now_tick = self.broker.current_tick();
                let nack_off = consumer.nack_offset.load(Ordering::Acquire);
                let effective_light = Stoplight::new(
                    consumer.light.cycle,
                    consumer.light.green,
                    consumer
                        .light
                        .offset
                        .wrapping_add(nack_off)
                        .checked_rem(consumer.light.cycle.max(1))
                        .unwrap_or(0),
                    consumer.light.distance,
                    consumer.light.speed,
                );

                // Find the next tick t >= now_tick at which sees_green is true.
                // `earliest_green_start` returns the absolute earliest tick in
                // [0, cycle); we shift by full cycles to land >= now_tick.
                let earliest = earliest_green_start(effective_light);
                let cycle = effective_light.cycle.max(1);
                // Smallest k such that earliest + k*cycle >= now_tick.
                let mut target = earliest;
                if target < now_tick {
                    let delta = now_tick - target;
                    let k = (delta + cycle - 1) / cycle;
                    target = target.saturating_add(k.saturating_mul(cycle));
                }

                self.broker.wait_for_tick(target);
            }

            // Honor the green prefetch width: respect a per-broker
            // in-flight cap of sum(green) (the antiqueue invariant).
            let depth = self.broker.in_flight.fetch_add(1, Ordering::AcqRel) + 1;
            self.broker.observe_peak(depth);

            let result = (consumer.handler)(&msg);

            self.broker.in_flight.fetch_sub(1, Ordering::Release);

            match result {
                Ok(()) => {
                    consumer.delivered.fetch_add(1, Ordering::Relaxed);
                    delivered += 1;
                }
                Err(_) => {
                    consumer.nacked.fetch_add(1, Ordering::Relaxed);
                    // Phase feedback: widen the offset by one tick so the
                    // next publish to this consumer admits later in the
                    // cycle. Caps at cycle-1 (further widening would wrap
                    // back to 0, defeating the purpose).
                    let cur = consumer.nack_offset.load(Ordering::Acquire);
                    let cap = consumer.light.cycle.saturating_sub(1);
                    if cur < cap {
                        consumer.nack_offset.store(cur + 1, Ordering::Release);
                    }
                }
            }
        }

        // Suppress unused-field warning: chirality is consumed by external
        // pipeline analyzers via the Channel API (below). The handler does
        // not pivot on it today.
        let _ = self.consumer_chirality_witness();

        Ok(delivered)
    }

    /// Compile-time witness that `chirality` is reachable; future
    /// `Channel` revisions will pivot dispatch on it.
    #[inline]
    fn consumer_chirality_witness(&self) -> Option<Chirality> {
        let consumers = self.broker.consumers.read().unwrap();
        consumers.values().next().map(|c| c.chirality)
    }
}

// ─────────────────────────────────────────────────────────────────────
// Channel (AMQP-shaped multiplexed connection)
// ─────────────────────────────────────────────────────────────────────

/// AMQP `Channel` shape — a multiplexed handle that pins QoS + a chamber
/// for a logical flow stage. Holds a reference to the broker; cheap.
pub struct Channel {
    broker: Arc<Broker>,
    chamber: Chirality,
    qos: QosSpec,
}

impl Channel {
    /// Construct a channel pinned to a chamber + QoS spec.
    pub fn new(broker: Arc<Broker>, chamber: Chirality, qos: QosSpec) -> Self {
        Self {
            broker,
            chamber,
            qos,
        }
    }

    /// Declare a consumer on this channel. The QoS prefetch maps to the
    /// Stoplight `green` width (per the AMQP mapping table). `cycle` is
    /// taken from `QosSpec::cycle` (defaults to 64 ticks).
    pub fn declare_consumer(
        &self,
        name: &str,
        offset: u32,
        handler: impl Fn(&Message) -> Result<(), String> + Send + Sync + 'static,
    ) {
        let light = Stoplight::resting(self.qos.cycle, self.qos.prefetch, offset);
        // Thread the QoS cost cert (AMQP `prefetch_size` reinterpreted) through
        // to the consumer so the cost-aware publish path can read it. The
        // default publish path ignores it, so this is transparent unless the
        // caller uses `publish_certified`.
        self.broker.declare_consumer_certified(
            name,
            light,
            self.chamber,
            self.qos.handler_cost_ns,
            handler,
        );
    }

    /// Producer handle for this channel's broker on a chosen exchange.
    pub fn producer(&self, exchange: &str) -> Producer {
        self.broker.producer(exchange)
    }

    /// Snapshot telemetry.
    pub fn telemetry(&self) -> Telemetry {
        self.broker.telemetry()
    }
}

// ─────────────────────────────────────────────────────────────────────
// Mock RabbitMQ baseline (for the bench)
// ─────────────────────────────────────────────────────────────────────

/// A bounded-prefetch tokio-mpsc-style queue we use as the "RabbitMQ"
/// baseline in the bench. *Not* a real AMQP impl — just the simplest
/// queue regime: a Mutex<VecDeque> with a per-consumer prefetch cap and
/// strict FIFO admission. The whole point is to measure what the
/// antiqueue regime change buys us.
#[cfg(not(target_arch = "wasm32"))]
pub mod mock_rabbit {
    use super::*;
    use std::collections::VecDeque;
    use std::sync::Condvar;

    /// Mock broker: one shared lock, one queue per consumer, FIFO drain
    /// with bounded prefetch.
    pub struct MockBroker {
        queues: Mutex<HashMap<String, VecDeque<Message>>>,
        notify: Condvar,
        /// Total messages published. Atomic counter, read by the bench.
        pub published: AtomicUsize,
        /// Total messages delivered (handler returned). Atomic counter.
        pub delivered: AtomicUsize,
        /// Peak observed queue depth. Atomic high-watermark.
        pub peak_depth: AtomicUsize,
    }

    impl MockBroker {
        /// Construct an empty mock broker.
        pub fn new() -> Arc<Self> {
            Arc::new(Self {
                queues: Mutex::new(HashMap::new()),
                notify: Condvar::new(),
                published: AtomicUsize::new(0),
                delivered: AtomicUsize::new(0),
                peak_depth: AtomicUsize::new(0),
            })
        }

        /// Declare a queue. Idempotent.
        pub fn declare_queue(&self, name: &str) {
            let mut q = self.queues.lock().unwrap();
            q.entry(name.to_string()).or_insert_with(VecDeque::new);
        }

        /// Publish to a queue. Lock-bounded; observes peak depth.
        pub fn publish(&self, queue: &str, msg: Message) {
            self.published.fetch_add(1, Ordering::Relaxed);
            let mut q = self.queues.lock().unwrap();
            let dq = q.entry(queue.to_string()).or_insert_with(VecDeque::new);
            dq.push_back(msg);
            let depth = dq.len();
            // Update peak.
            let mut prev = self.peak_depth.load(Ordering::Relaxed);
            while depth > prev {
                match self.peak_depth.compare_exchange_weak(
                    prev,
                    depth,
                    Ordering::Relaxed,
                    Ordering::Relaxed,
                ) {
                    Ok(_) => break,
                    Err(seen) => prev = seen,
                }
            }
            drop(q);
            self.notify.notify_all();
        }

        /// Run a consumer on `queue` with `prefetch` parallelism and a
        /// `service` per-message handler cost (busy-spin). Returns when
        /// `total` messages have been delivered.
        ///
        /// Latency is measured **enqueue→deliver-complete**: the message
        /// body must start with the 16-byte little-endian nanoseconds-
        /// since-`epoch` timestamp encoded by the caller at publish time.
        /// `epoch` is the shared wall-clock origin both producer and
        /// consumer use as `Instant::now()` reference. This is the
        /// honest queue-vs-antiqueue comparison: a queue's pathology
        /// lives in the wait-before-service, not in service itself.
        pub fn consume_blocking(
            self: &Arc<Self>,
            queue: &str,
            prefetch: usize,
            service: Duration,
            total: usize,
            epoch: std::time::Instant,
        ) -> Vec<Duration> {
            let latencies = Arc::new(Mutex::new(Vec::with_capacity(total)));
            let mut handles = Vec::with_capacity(prefetch);
            for _ in 0..prefetch {
                let me = Arc::clone(self);
                let q = queue.to_string();
                let lats = Arc::clone(&latencies);
                handles.push(std::thread::spawn(move || {
                    loop {
                        let msg = {
                            let mut guard = me.queues.lock().unwrap();
                            loop {
                                let dq = guard.get_mut(&q).unwrap();
                                if let Some(m) = dq.pop_front() {
                                    break m;
                                }
                                if me.delivered.load(Ordering::Acquire) >= total {
                                    return;
                                }
                                guard = me.notify.wait(guard).unwrap();
                            }
                        };
                        // Service: busy-spin.
                        let svc_start = std::time::Instant::now();
                        let deadline = svc_start + service;
                        while std::time::Instant::now() < deadline {
                            std::hint::spin_loop();
                        }
                        // Decode publish-time embedded in body[0..16].
                        let enq_ns = read_u128_le(&msg.body);
                        let now_ns = epoch.elapsed().as_nanos();
                        let elapsed = Duration::from_nanos(
                            now_ns.saturating_sub(enq_ns).min(u64::MAX as u128) as u64,
                        );
                        lats.lock().unwrap().push(elapsed);
                        let done = me.delivered.fetch_add(1, Ordering::AcqRel) + 1;
                        if done >= total {
                            me.notify.notify_all();
                            return;
                        }
                    }
                }));
            }
            for h in handles {
                h.join().unwrap();
            }
            let mut guard = latencies.lock().unwrap();
            std::mem::take(&mut *guard)
        }
    }

    /// Read a little-endian u128 from the first 16 bytes of `body`.
    /// Used to decode the embedded publish-time. Returns 0 if `body` is
    /// too short.
    pub fn read_u128_le(body: &[u8]) -> u128 {
        if body.len() < 16 {
            return 0;
        }
        let mut buf = [0u8; 16];
        buf.copy_from_slice(&body[..16]);
        u128::from_le_bytes(buf)
    }
}

// ─────────────────────────────────────────────────────────────────────
// Tests
