#[cfg(test)]
mod tests {
    use super::*;
    use std::sync::atomic::AtomicUsize;
    use std::time::Instant;

    #[test]
    fn declare_consumer_and_publish_default_exchange() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        let counter = Arc::new(AtomicUsize::new(0));
        let c2 = Arc::clone(&counter);
        broker.declare_consumer("tasks.compute", Stoplight::open(8), move |_msg| {
            c2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        let p = broker.producer("");
        for _ in 0..10 {
            p.publish("tasks.compute", b"hello".to_vec()).unwrap();
        }
        assert_eq!(counter.load(Ordering::Acquire), 10);
        let t = broker.telemetry();
        assert_eq!(t.published, 10);
        assert_eq!(t.delivered, 10);
        assert_eq!(t.dropped, 0);
    }

    #[test]
    fn hot_direct_route_decision_reuses_cache_after_observations() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        let counter = Arc::new(AtomicUsize::new(0));
        let c2 = Arc::clone(&counter);
        broker.declare_consumer("tasks.compute", Stoplight::open(8), move |_| {
            c2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });

        let p = broker.producer("");
        for _ in 0..ROUTE_CACHE_ADMISSION_OBSERVATIONS {
            p.publish("tasks.compute", b"hot".to_vec()).unwrap();
        }
        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 0);

        p.publish("tasks.compute", b"cached".to_vec()).unwrap();

        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 1);
        assert_eq!(counter.load(Ordering::Acquire), 4);
    }

    #[test]
    fn unmatched_publish_drops_message() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        let p = broker.producer("");
        let delivered = p.publish("nothing.here", b"void".to_vec()).unwrap();
        assert_eq!(delivered, 0);
    }

    #[test]
    fn topic_exchange_wildcard_routing() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        broker.declare_exchange("logs", ExchangeKind::Topic);
        let hits = Arc::new(AtomicUsize::new(0));
        let h2 = Arc::clone(&hits);
        broker.declare_consumer("error.handler", Stoplight::open(4), move |_| {
            h2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.bind(
            "logs",
            "error.handler",
            BindingKey::Topic("logs.error.*".into()),
        );
        let p = broker.producer("logs");
        p.publish("logs.error.fatal", b"!".to_vec()).unwrap();
        p.publish("logs.info.boot", b"i".to_vec()).unwrap();
        assert_eq!(hits.load(Ordering::Acquire), 1);
    }

    #[test]
    fn hot_topic_route_decision_reuses_cache_after_observations() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        broker.declare_exchange("logs", ExchangeKind::Topic);
        let hits = Arc::new(AtomicUsize::new(0));
        let h2 = Arc::clone(&hits);
        broker.declare_consumer("error.handler", Stoplight::open(4), move |_| {
            h2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.bind(
            "logs",
            "error.handler",
            BindingKey::Topic("logs.error.*".into()),
        );

        let p = broker.producer("logs");
        for _ in 0..ROUTE_CACHE_ADMISSION_OBSERVATIONS {
            p.publish("logs.error.fatal", b"!".to_vec()).unwrap();
        }
        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 0);

        p.publish("logs.error.fatal", b"!".to_vec()).unwrap();

        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 1);
        assert_eq!(hits.load(Ordering::Acquire), 4);
    }

    #[test]
    fn bind_invalidates_hot_route_decision() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        broker.declare_exchange("logs", ExchangeKind::Topic);

        let errors = Arc::new(AtomicUsize::new(0));
        let e2 = Arc::clone(&errors);
        broker.declare_consumer("error.handler", Stoplight::open(4), move |_| {
            e2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.bind(
            "logs",
            "error.handler",
            BindingKey::Topic("logs.error.*".into()),
        );

        let p = broker.producer("logs");
        for _ in 0..=ROUTE_CACHE_ADMISSION_OBSERVATIONS {
            p.publish("logs.error.fatal", b"!".to_vec()).unwrap();
        }
        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 1);

        let audits = Arc::new(AtomicUsize::new(0));
        let a2 = Arc::clone(&audits);
        broker.declare_consumer("audit.handler", Stoplight::open(4), move |_| {
            a2.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.bind("logs", "audit.handler", BindingKey::Topic("logs.#".into()));

        assert!(broker.route_cache.read().unwrap().entries.is_empty());
        p.publish("logs.error.fatal", b"!".to_vec()).unwrap();

        assert_eq!(broker.route_cache_hits.load(Ordering::Acquire), 1);
        assert_eq!(errors.load(Ordering::Acquire), 5);
        assert_eq!(audits.load(Ordering::Acquire), 1);
    }

    #[test]
    fn fanout_exchange_broadcasts() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        broker.declare_exchange("broadcast", ExchangeKind::Fanout);
        let a = Arc::new(AtomicUsize::new(0));
        let b = Arc::new(AtomicUsize::new(0));
        let aa = Arc::clone(&a);
        let bb = Arc::clone(&b);
        broker.declare_consumer("sub.a", Stoplight::open(4), move |_| {
            aa.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.declare_consumer("sub.b", Stoplight::open(4), move |_| {
            bb.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        broker.bind("broadcast", "sub.a", BindingKey::Direct("sub.a".into()));
        broker.bind("broadcast", "sub.b", BindingKey::Direct("sub.b".into()));
        let p = broker.producer("broadcast");
        p.publish("ignored", b"x".to_vec()).unwrap();
        assert_eq!(a.load(Ordering::Acquire), 1);
        assert_eq!(b.load(Ordering::Acquire), 1);
    }

    #[test]
    fn fanout_routes_by_stable_green_window_order() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        broker.declare_exchange("broadcast", ExchangeKind::Fanout);
        let seen = Arc::new(Mutex::new(Vec::<String>::new()));
        for (name, light, chirality) in [
            ("late", Stoplight::resting(16, 1, 8), Chirality::Compression),
            (
                "compression",
                Stoplight::resting(16, 1, 0),
                Chirality::Compression,
            ),
            ("intake", Stoplight::resting(16, 1, 0), Chirality::Intake),
        ] {
            let seen_clone = Arc::clone(&seen);
            broker.declare_consumer_with_chirality(name, light, chirality, move |_| {
                seen_clone.lock().unwrap().push(name.to_string());
                Ok(())
            });
            broker.bind("broadcast", name, BindingKey::Direct(name.into()));
        }

        let p = broker.producer("broadcast");
        p.publish("ignored", b"x".to_vec()).unwrap();

        assert_eq!(
            *seen.lock().unwrap(),
            vec![
                "intake".to_string(),
                "compression".to_string(),
                "late".to_string()
            ]
        );
    }

    #[test]
    fn nack_widens_offset() {
        let broker = Broker::with_tick(Duration::from_micros(1));
        let fail_first = Arc::new(AtomicUsize::new(0));
        let fail2 = Arc::clone(&fail_first);
        broker.declare_consumer("flaky", Stoplight::resting(8, 1, 0), move |_| {
            let n = fail2.fetch_add(1, Ordering::Relaxed);
            if n < 2 {
                Err("nope".into())
            } else {
                Ok(())
            }
        });
        let p = broker.producer("");
        for _ in 0..5 {
            p.publish("flaky", b"r".to_vec()).unwrap();
        }
        let t = broker.telemetry();
        assert_eq!(t.published, 5);
        assert_eq!(t.nacked, 2);
        assert_eq!(t.delivered, 3);
    }

    #[test]
    fn channel_declares_consumer_with_qos_prefetch() {
        let broker = Broker::local();
        let chan = Channel::new(
            Arc::clone(&broker),
            Chirality::Compression,
            QosSpec {
                prefetch: 4,
                cycle: 16,
                handler_cost_ns: 0,
            },
        );
        let n = Arc::new(AtomicUsize::new(0));
        let nn = Arc::clone(&n);
        chan.declare_consumer("work", 0, move |_| {
            nn.fetch_add(1, Ordering::Relaxed);
            Ok(())
        });
        let p = chan.producer("");
        for _ in 0..3 {
            p.publish("work", b"k".to_vec()).unwrap();
        }
        assert_eq!(n.load(Ordering::Acquire), 3);
    }

    #[test]
    fn certified_cheap_message_runs_laminar_red() {
        // RED crossover: a cheap handler (cost < gate) must NOT pay the
        // corridor stagger — the cost-aware path runs it inline immediately,
        // so even a consumer whose green window starts FAR in the future
        // (offset deep into a long cycle) delivers right away.
        //
        // tick = 1ms; per_message_gate_ns ~= 1_000_200ns. handler_cost_ns = 1
        // (1ns << gate) ⇒ certified_light = RED ⇒ inline.
        let broker = Broker::local(); // 1ms tick → ~1ms gate cost
        let n = Arc::new(AtomicUsize::new(0));
        let nn = Arc::clone(&n);
        // Green window opens at offset 60 of a 66-cycle: with a 1ms tick the
        // DEFAULT (staggered) path would block ~60ms per message. RED must
        // bypass that entirely.
        broker.declare_consumer_certified(
            "cheap",
            Stoplight::resting(66, 1, 60),
            Chirality::Compression,
            1, // 1ns certified handler cost — far below the ms-scale gate
            move |_| {
                nn.fetch_add(1, Ordering::Relaxed);
                Ok(())
            },
        );
        let p = broker.producer("");
        let start = Instant::now();
        for _ in 0..5 {
            assert_eq!(p.publish_certified("cheap", b"x".to_vec()).unwrap(), 1);
        }
        let elapsed = start.elapsed();
        assert_eq!(n.load(Ordering::Acquire), 5, "all cheap messages delivered");
        // Inline (RED): 5 messages must finish in well under one stagger
        // (~60ms). Generous 20ms ceiling guards against the staggered path.
        assert!(
            elapsed < Duration::from_millis(20),
            "RED must run laminar (inline); took {elapsed:?} — looks staggered"
        );
    }

    #[test]
    fn certified_crossover_decision_is_red_or_green_never_yellow() {
        // Pin the gate decision directly against the Lean contract
        // (`certified_never_yellow` / `certified_is_red_or_green`): with the
        // antiqueue per-message gate as `g`, a cert `r` is GREEN iff g < r,
        // RED otherwise — and never YELLOW.
        let broker = Broker::with_tick(Duration::from_micros(1)); // 1us tick
        let gate = broker.per_message_gate_ns(); // ~1000 + 200 = 1200ns
        // Below crossover: cheap handler stays RED.
        assert_eq!(certified_light(1, gate), Light::Red);
        assert_eq!(certified_light(gate, gate), Light::Red); // r == g ⇒ RED
        // Above crossover: heavy handler opens the door (GREEN).
        assert_eq!(certified_light(gate + 1, gate), Light::Green);
        assert_eq!(certified_light(10_000_000, gate), Light::Green);
        // Never YELLOW for any certified cost.
        for r in [0u64, 1, gate, gate + 1, u64::MAX] {
            assert_ne!(certified_light(r, gate), Light::Yellow);
        }
    }

    #[test]
    fn certified_heavy_message_still_staggers_green() {
        // GREEN crossover: a heavy handler (cost > gate) opens the door — the
        // cost-aware path staggers exactly like the default. With a tiny tick
        // the stagger is cheap, so we just assert correct delivery + that the
        // cost gate routed it through the staggered (green-window) door by
        // confirming the in-flight cap (antiqueue invariant) held.
        let broker = Broker::with_tick(Duration::from_micros(1));
        let gate = broker.per_message_gate_ns();
        let n = Arc::new(AtomicUsize::new(0));
        let nn = Arc::clone(&n);
        broker.declare_consumer_certified(
            "heavy",
            Stoplight::open(8), // full-green: stagger is a no-op wait but taken
            Chirality::Compression,
            gate.saturating_mul(1000), // certified heavy ⇒ GREEN
            move |_| {
                nn.fetch_add(1, Ordering::Relaxed);
                Ok(())
            },
        );
        let p = broker.producer("");
        for _ in 0..4 {
            assert_eq!(p.publish_certified("heavy", b"x".to_vec()).unwrap(), 1);
        }
        assert_eq!(n.load(Ordering::Acquire), 4);
        // Stagger honored the prefetch/in-flight cap.
        assert!(broker.telemetry().peak_in_flight <= 1);
    }

    #[test]
    fn certified_unattested_cost_stays_on_default_staggered_door() {
        // cost = 0 (unattested) ⇒ conservatively GREEN: behaves like the
        // default staggered publish. Delivery must still be correct.
        let broker = Broker::with_tick(Duration::from_micros(1));
        let n = Arc::new(AtomicUsize::new(0));
        let nn = Arc::clone(&n);
        broker.declare_consumer_certified(
            "unattested",
            Stoplight::open(8),
            Chirality::Compression,
            0, // unattested
            move |_| {
                nn.fetch_add(1, Ordering::Relaxed);
                Ok(())
            },
        );
        let p = broker.producer("");
        for _ in 0..3 {
            p.publish_certified("unattested", b"x".to_vec()).unwrap();
        }
        assert_eq!(n.load(Ordering::Acquire), 3);
    }

    #[test]
    fn stoplight_ext_constructors_pin_lean_predicate() {
        let l = Stoplight::resting(10, 3, 7);
        // arrivalPhase(0, l) = (0 + 0 + 7) mod 10 = 7. seesGreen iff < 3.
        assert!(!sees_green(0, l));
        // The earliest green tick: t with (t+7) mod 10 < 3, i.e. t in {3,4,5}.
        let t = earliest_green_start(l);
        assert_eq!(t, 3);
        assert!(sees_green(t, l));

        let o = Stoplight::open(10);
        assert!(sees_green(0, o));
        assert!(sees_green(9, o));
    }
}
